package com.jdmedia.controller;
import com.jdmedia.service.AppContext;import javafx.fxml.FXML;import javafx.scene.control.*;
public final class StatusBarController {private final AppContext context;@FXML private Label statusLabel,percentLabel;@FXML private ProgressBar statusProgress;public StatusBarController(AppContext context){this.context=context;}@FXML public void initialize(){statusLabel.textProperty().bind(context.status().messageProperty());statusProgress.progressProperty().bind(context.status().progressProperty());statusProgress.visibleProperty().bind(context.status().progressProperty().greaterThanOrEqualTo(0));statusProgress.managedProperty().bind(statusProgress.visibleProperty());percentLabel.visibleProperty().bind(statusProgress.visibleProperty());percentLabel.managedProperty().bind(percentLabel.visibleProperty());context.status().progressProperty().addListener((o,a,b)->percentLabel.setText(b.doubleValue()<0?"":String.format("%.0f %%",b.doubleValue()*100)));}}
